solutions.cpp:
// Solution
#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int findFirstDuplicate(vector<int>& nums) {
        int first_duplicate = -1;
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] != nums[i + 1]) {
                first_duplicate = nums[i];
                break;
            }
        }
        return first_duplicate;
    }
};

int main() {
    Solution solution;
    vector<int> nums = {1, 2, 3, 4, 5, 5};
    int result = solution.findFirstDuplicate(nums);
    cout << result << endl;
    return 0;
}

